#!/bin/bash
whois $1 | awk -F': ' 'BEGIN {IGNORECASE=1; f["Registrant Name"]="Registrant Name"; f["Registrant Organization"]="Registrant Organization"; f["Registrant Street"]="Registrant Street "; f["Registrant City"]="Registrant City"; f["Registrant State/Province"]="Registrant State/Province"; f["Registrant Postal Code"]="Registrant Postal Code"; f["Registrant Country"]="Registrant Country"; f["Registrant Phone"]="Registrant Phone"; f["Registrant Phone Ext"]="Registrant Phone Ext:"; f["Registrant Fax"]="Registrant Fax"; f["Registrant Fax Ext"]="Registrant Fax Ext:"; f["Registrant Email"]="Registrant Email"; f["Admin Name"]="Admin Name"; f["Admin Organization"]="Admin Organization"; f["Admin Street"]="Admin Street "; f["Admin City"]="Admin City"; f["Admin State/Province"]="Admin State/Province"; f["Admin Postal Code"]="Admin Postal Code"; f["Admin Country"]="Admin Country"; f["Admin Phone"]="Admin Phone"; f["Admin Phone Ext"]="Admin Phone Ext:"; f["Admin Fax"]="Admin Fax"; f["Admin Fax Ext"]="Admin Fax Ext:"; f["Admin Email"]="Admin Email"; f["Tech Name"]="Tech Name"; f["Tech Organization"]="Tech Organization"; f["Tech Street"]="Tech Street "; f["Tech City"]="Tech City"; f["Tech State/Province"]="Tech State/Province"; f["Tech Postal Code"]="Tech Postal Code"; f["Tech Country"]="Tech Country"; f["Tech Phone"]="Tech Phone"; f["Tech Phone Ext"]="Tech Phone Ext:"; f["Tech Fax"]="Tech Fax"; f["Tech Fax Ext"]="Tech Fax Ext:"; f["Tech Email"]="Tech Email"; split("Registrant Name,Registrant Organization,Registrant Street,Registrant City,Registrant State/Province,Registrant Postal Code,Registrant Country,Registrant Phone,Registrant Phone Ext,Registrant Fax,Registrant Fax Ext,Registrant Email,Admin Name,Admin Organization,Admin Street,Admin City,Admin State/Province,Admin Postal Code,Admin Country,Admin Phone,Admin Phone Ext,Admin Fax,Admin Fax Ext,Admin Email,Tech Name,Tech Organization,Tech Street,Tech City,Tech State/Province,Tech Postal Code,Tech Country,Tech Phone,Tech Phone Ext,Tech Fax,Tech Fax Ext,Tech Email", order, ",")} {gsub(/^[ \t]+|[ \t]+$/, "", $1); gsub(/^[ \t]+|[ \t]+$/, "", $2); if ($1 in f) v[$1]=$2} END {for (i=1; i<=36; i++) {k=order[i]; out=f[k] "," v[k]; if (i==36) printf "%s", out; else print out}}' > $1.csv
